// Normalise and validate inbound lead data
const body = $input.first().json.body || $input.first().json;

const normalised = {
  id: body.id || body.contact_id || null,
  full_name: (body.full_name || body.name || '').trim(),
  email: (body.email || '').toLowerCase().trim(),
  phone: (body.phone || body.phone_number || '').replace(/\s/g, ''),
  source: body.source || body.lead_source || 'website',
  budget: Number(body.budget) || 0,
  zone_interest: body.zone_interest || body.zone || body.location || '',
  typology: body.typology || body.property_type || '',
  timeline: body.timeline || 'unknown',
  motivation_score: Number(body.motivation_score) || 3,
  message: body.message || body.notes || '',
  created_at: body.created_at || new Date().toISOString()
};

// Basic validation
if (!normalised.email && !normalised.phone) {
  throw new Error('Lead sem email nem telefone — descartado');
}

// Sanitise phone to E.164 (basic PT/ES)
if (normalised.phone && !normalised.phone.startsWith('+')) {
  if (normalised.phone.startsWith('9') || normalised.phone.startsWith('2')) {
    normalised.phone = '+351' + normalised.phone;
  } else if (normalised.phone.startsWith('6') || normalised.phone.startsWith('7')) {
    normalised.phone = '+34' + normalised.phone;
  }
}

return [{ json: normalised }];

// Lead Scoring Engine — Agency Group
const lead = $('Code — Normalizar Lead').item.json;
const clearbit = $('HTTP — Clearbit Enrich').item.json || {};
const hunter = $('HTTP — Hunter Email Verify').item.json || {};

let score = 0;
const breakdown = {};

// Budget scoring
if (lead.budget > 1_000_000) {
  score += 30; breakdown.budget = '+30 (>€1M)';
} else if (lead.budget > 500_000) {
  score += 20; breakdown.budget = '+20 (>€500K)';
} else if (lead.budget > 200_000) {
  score += 10; breakdown.budget = '+10 (>€200K)';
} else {
  breakdown.budget = '+0';
}

// Timeline scoring
if (lead.timeline === 'immediate' || lead.timeline === 'imediato') {
  score += 25; breakdown.timeline = '+25 (imediato)';
} else if (lead.timeline === '3months' || lead.timeline === '3_months') {
  score += 15; breakdown.timeline = '+15 (3 meses)';
} else if (lead.timeline === '6months' || lead.timeline === '6_months') {
  score += 8; breakdown.timeline = '+8 (6 meses)';
} else {
  breakdown.timeline = '+0';
}

// Motivation scoring
if (lead.motivation_score >= 4) {
  score += 15; breakdown.motivation = '+15 (motivação alta)';
} else if (lead.motivation_score >= 3) {
  score += 8; breakdown.motivation = '+8 (motivação média)';
}

// Source scoring
const sourceScores = {
  referral: 20, referido: 20,
  idealista_premium: 10, idealista: 8,
  website: 5, portais: 5,
  cold: 2
};
const srcScore = sourceScores[lead.source?.toLowerCase()] || 3;
score += srcScore;
breakdown.source = `+${srcScore} (${lead.source})`;

// Contact completeness
if (lead.email) { score += 5; breakdown.email = '+5'; }
if (lead.phone) { score += 5; breakdown.phone = '+5'; }

// Clearbit enrichment bonus
if (clearbit.person?.linkedin?.handle) {
  score += 5; breakdown.linkedin = '+5';
}
if (clearbit.company?.name) {
  score += 3; breakdown.company = '+3 (empresa identificada)';
}

// Hunter email quality
const hunterStatus = hunter.data?.status;
if (hunterStatus === 'valid') {
  score += 3; breakdown.email_verified = '+3';
} else if (hunterStatus === 'risky') {
  score -= 5; breakdown.email_verified = '-5 (email arriscado)';
}

score = Math.min(100, Math.max(0, score));

// Routing
let routing;
if (score >= 70) routing = 'hot';
else if (score >= 40) routing = 'warm';
else routing = 'cold';

// Enrich lead data with Clearbit
const enriched = {
  ...lead,
  lead_score: score,
  score_breakdown: breakdown,
  routing,
  clearbit_person: clearbit.person || null,
  clearbit_company: clearbit.company || null,
  email_verified: hunterStatus === 'valid',
  linkedin_url: clearbit.person?.linkedin?.handle
    ? `https://linkedin.com/in/${clearbit.person.linkedin.handle}`
    : null
};

return [{ json: enriched }];

