Dados do lead:
- Nome: {{ $json.full_name }}
- Budget: €{{ $json.budget }}
- Zona interesse: {{ $json.zone_interest }}
- Tipologia: {{ $json.typology }}
- Timeline: {{ $json.timeline }}
- Score calculado: {{ $json.lead_score }}/100
- Fonte: {{ $json.source }}
- Mensagem: {{ $json.message }}
- Empresa (Clearbit): {{ $json.clearbit_company?.name || 'desconhecida' }}

Responda com este JSON exacto (sem markdown):
{
  "intent": "buy" | "rent" | "invest" | "unclear",
  "budget_realistic": true | false,
  "urgency": "high" | "medium" | "low",
  "buyer_profile": "end_user" | "investor" | "relocating" | "golden_visa" | "unclear",
  "language_detected": "pt" | "en" | "fr" | "es" | "other",
  "score_adjustment": -10 | -5 | 0 | 5 | 10,
  "suggested_first_message": "mensagem de boas-vindas personalizada em 1-2 frases no idioma detectado",
  "next_action": "call" | "email" | "whatsapp" | "nurture",
  "classification_notes": "observação curta (max 15 palavras)"
}

parameters.jsCode:
// Parse Claude response and merge with lead data
const lead = $('Code — Lead Scoring').item.json;
const claudeRaw = $input.first().json.text || $input.first().json.content?.[0]?.text || '{}';

let classification;
try {
  // Strip markdown code blocks if present
  const cleaned = claudeRaw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  classification = JSON.parse(cleaned);
} catch (e) {
  classification = {
    intent: 'unclear',
    budget_realistic: true,
    urgency: 'medium',
    buyer_profile: 'unclear',
    language_detected: 'pt',
    score_adjustment: 0,
    suggested_first_message: `Olá ${lead.full_name}, obrigado pelo seu contacto com a Agency Group. Terei todo o gosto em ajudá-lo/a.`,
    next_action: 'email',
    classification_notes: 'Classificação automática fallback'
  };
}

// Apply score adjustment from Claude
const finalScore = Math.min(100, Math.max(0, lead.lead_score + (classification.score_adjustment || 0)));

const finalLead = {
  ...lead,
  lead_score: finalScore,
  intent: classification.intent,
  budget_realistic: classification.budget_realistic,
  urgency: classification.urgency,
  buyer_profile: classification.buyer_profile,
  language_detected: classification.language_detected,
  suggested_first_message: classification.suggested_first_message,
  next_action: classification.next_action,
  classification_notes: classification.classification_notes,
  // Re-evaluate routing with final score
  routing: finalScore >= 70 ? 'hot' : finalScore >= 40 ? 'warm' : 'cold'
};

return [{ json: finalLead }];

